function e(e){if(!e)return`尚未检测`;let t=new Date(e);return Number.isNaN(t.getTime())?`时间未知`:new Intl.DateTimeFormat(`zh-CN`,{month:`2-digit`,day:`2-digit`,hour:`2-digit`,minute:`2-digit`}).format(t)}function t(e){if(!e)return`尚未检测`;let t=new Date(e).getTime();if(Number.isNaN(t))return`时间未知`;let n=Math.round((t-Date.now())/6e4),r=new Intl.RelativeTimeFormat(`zh-CN`,{numeric:`auto`});if(Math.abs(n)<60)return r.format(n,`minute`);let i=Math.round(n/60);return Math.abs(i)<24?r.format(i,`hour`):r.format(Math.round(i/24),`day`)}function n(e,t){let n=Number(e);if(!Number.isFinite(n))return`${e} ${t}`;let r=Math.abs(n)>=1e3?0:2;return`${new Intl.NumberFormat(`zh-CN`,{maximumFractionDigits:r}).format(n)} ${t}`}function r(e){try{return new URL(e).host}catch{return e}}export{r as i,n,t as r,e as t};